import { Component } from '@angular/core';
import { AuthService } from './services/auth.service';
import { Router } from '@angular/router';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html'
})
export class AppComponent {
  constructor(public auth: AuthService, private router: Router) {}

  public logout(): void {
    this.auth.clear();
    this.router.navigate(['/']);
  }
}
<header>
  <nav>
    <a class="brand" routerLink="/">BusBook</a>
    <a routerLink="/" routerLinkActive="active" [routerLinkActiveOptions]="{exact:true}">Home</a>
    <a routerLink="/search" routerLinkActive="active">Search Buses</a>
    <a *ngIf="auth.isAuthenticated()" routerLink="/dashboard" routerLinkActive="active">My Trips</a>
    <a *ngIf="auth.hasRole('BusOperator')" routerLink="/operator" routerLinkActive="active">Operator</a>
    <a *ngIf="auth.hasRole('Admin')" routerLink="/admin" routerLinkActive="active">Admin</a>
    <span style="flex:1"></span>
    <a *ngIf="!auth.isAuthenticated()" routerLink="/auth" class="nav-auth-btn">Login / Sign Up</a>
    <ng-container *ngIf="auth.isAuthenticated()">
      <span class="nav-greeting">Hi, {{ auth.user?.name }}</span>
      <button class="nav-logout-btn" (click)="logout()">Logout</button>
    </ng-container>
  </nav>
</header>
<div class="container">
  <router-outlet></router-outlet>
</div>
